425	function renderConversation(detail: EntireSessionDetailModel, includeDayInTimestamp: boolean): string {
426		return detail.turns
427			.filter((turn) => Boolean(turn.text) || turn.toolActivities.length > 0)
428			.map((turn) => renderTurn(turn, includeDayInTimestamp))
429			.join("");
430	}
