432	function renderTurn(turn: EntireSessionDetailModel["turns"][number], includeDayInTimestamp: boolean): string {
433		const timestampLabel = formatDetailTimestamp(turn.timestamp, includeDayInTimestamp);
434	
435		return `<article class="turn turn--${escapeHtml(turn.actor.kind)}">
436			<div class="turn__meta">
437				${renderAvatar(turn.actor)}
438				${timestampLabel ? `<time class="timestamp">${escapeHtml(timestampLabel)}</time>` : ""}
439			</div>
440			<div class="turn__body">
441				${turn.text ? `<p class="turn__text">${escapeHtml(turn.text)}</p>` : ""}
442				${turn.toolActivities.length > 0 ? `<div class="tools">${turn.toolActivities.map((activity) => renderToolActivity(activity)).join("")}</div>` : ""}
443			</div>
444		</article>`;
445	}
