447	function renderAvatar(actor: EntireSessionDetailModel["turns"][number]["actor"]): string {
448		if (actor.imageUri) {
449			return `<span class="avatar"><img src="${escapeHtml(actor.imageUri)}" alt="" /></span>`;
450		}
451	
452		return `<span class="avatar">${escapeHtml(actor.initials)}</span>`;
453	}
