455	function renderToolActivity(activity: EntireSessionDetailModel["turns"][number]["toolActivities"][number]): string {
456		return `<div class="tool__content">
457			<div class="tool__label">
458				<span class="tool__kind">Tool</span>
459				<span>${escapeHtml(activity.label)}</span>
460			</div>
461			${activity.detail ? `<p class="tool__detail">${escapeHtml(activity.detail)}</p>` : ""}
462		</div>`;
463	}
