465	function formatDetailTimestamp(timestamp: string | undefined, includeDayInTimestamp: boolean): string | undefined {
466		if (!timestamp) {
467			return undefined;
468		}
469	
470		const date = new Date(timestamp);
471		if (Number.isNaN(date.getTime())) {
472			return timestamp;
473		}
474	
475		return new Intl.DateTimeFormat("en", includeDayInTimestamp ? {
476			month: "short",
477			day: "numeric",
478			hour: "numeric",
479			minute: "2-digit",
480		} : {
481			hour: "numeric",
482			minute: "2-digit",
483		}).format(date);
484	}
485	
486	function shouldIncludeDayInTimestamp(durationMs: number | undefined): boolean {
487		return typeof durationMs === "number" && Number.isFinite(durationMs) && durationMs >= 86_400_000;
488	}
489	
490	function formatDuration(durationMs: number | undefined): string | undefined {
491		if (durationMs === undefined || !Number.isFinite(durationMs) || durationMs < 0) {
492			return undefined;
493		}
494	
495		const totalSeconds = Math.max(0, Math.floor(durationMs / 1000));
496		const days = Math.floor(totalSeconds / 86_400);
497		const hours = Math.floor((totalSeconds % 86_400) / 3_600);
498		const minutes = Math.floor((totalSeconds % 3_600) / 60);
499		const seconds = totalSeconds % 60;
500	
501		if (days > 0) {
502			return hours > 0 ? `${days}d ${hours}h` : `${days}d`;
503		}
504	
505		if (hours > 0) {
506			return minutes > 0 ? `${hours}h ${minutes}m` : `${hours}h`;
507		}
508	
509		if (minutes > 0) {
510			return seconds > 0 && minutes < 10 ? `${minutes}m ${seconds}s` : `${minutes}m`;
511		}
512	
513		return `${seconds}s`;
514	}
515	
516	function formatTokenCount(count: number): string {
517		if (count >= 1_000_000) {
518			return `${(count / 1_000_000).toFixed(1)}M`;
519		}
