import { NormalizedRewindPoint } from "./rewindIndex";
import type { CheckpointSummaryRecord, InitialAttribution, SummaryRecord } from "./types";

/** Normalized live-or-historical session status used by card and detail models. */
export type SessionStatus = "ACTIVE" | "IDLE" | "ENDED";

/** Session-tree selection context used to resolve a session detail payload. */
export interface SessionDetailTarget {
	source: "live" | "checkpoint";
	sessionId: string;
	checkpointIds: string[];
	promptPreview: string;
	status: SessionStatus;
	agent?: string;
	model?: string;
	author?: string;
	startedAt?: string;
	lastActivityAt?: string;
	durationMs?: number;
	attribution?: InitialAttribution;
	checkpointCount: number;
	turnCount?: number;
	toolCount?: number;
	tokenCount?: number;
	transcriptPath?: string;
}

/** Avatar/logo metadata for a rendered conversation turn. */
export interface SessionConversationActor {
	kind: "user" | "agent";
	initials: string;
	imageUri?: string;
}

/** Compact tool activity row rendered inline within a conversation turn. */
export interface SessionToolActivity {
	id: string;
	kind: "tool_use";
	label: string;
	detail?: string;
}

/** Human-readable conversation turn rendered in the session details panel. */
export interface SessionConversationTurn {
	id: string;
	actor: SessionConversationActor;
	timestamp?: string;
	text?: string;
	toolActivities: SessionToolActivity[];
}

/** Structured detail payload for the session details webview panel. */
export interface EntireSessionDetailModel {
	sessionId: string;
	source: "live" | "checkpoint";
	promptPreview: string;
	status: SessionStatus;
	startedAt?: string;
	lastActivityAt?: string;
	durationMs?: number;
	checkpointCount: number;
	turnCount?: number;
	toolCount?: number;
	tokenCount?: number;
	attribution?: InitialAttribution;
	model?: string;
	transcriptAvailable: boolean;
	turns: SessionConversationTurn[];
}

/** Per-file diff statistics aggregated from active-branch associated commits. */
export interface FileDiffStat {
	path: string;
	additions?: number;
	deletions?: number;
}

/** Rollup of changed-file counts and numeric line deltas for a checkpoint. */
export interface DiffSummaryModel {
	filesChanged: number;
	linesAdded?: number;
	linesRemoved?: number;
}

/** Commit metadata associated with a checkpoint on the active branch. */
export interface AssociatedCommitModel {
	sha: string;
	shortSha: string;
	message: string;
	body?: string;
	authorName: string;
	authorEmail?: string;
	authoredAt?: string;
	fileStats?: FileDiffStat[];
	patchText?: string;
}

/** Current rewindability and rewind-mode metadata for a checkpoint or temporary point. */
export interface RewindAvailability {
	isAvailable: boolean;
	pointId?: string;
	checkpointId?: string;
	isLogsOnly: boolean;
	isTaskCheckpoint: boolean;
	isTemporary: boolean;
	message?: string;
	sessionId?: string;
}

/** Normalized model for a session browser card. */
export interface EntireSessionCard {
	id: string;
	sessionId: string;
	promptPreview: string;
	displayHash?: string;
	checkpointIds: string[];
	agent?: string;
	model?: string;
	status: SessionStatus;
	author?: string;
	branch?: string;
	createdAt?: string;
	lastActivityAt?: string;
	durationMs?: number;
	stepCount?: number;
	toolCount?: number;
	tokenCount?: number;
	attribution?: InitialAttribution;
	checkpointCount: number;
	latestCheckpointId?: string;
	latestAssociatedCommitSha?: string;
	isLiveOnly: boolean;
	searchText: string;
}

/** Normalized model for the live active-session tree view. */
export interface EntireActiveSessionCard {
	id: string;
	sessionId: string;
	status: SessionStatus;
	phase?: string;
	promptPreview: string;
	agent?: string;
	model?: string;
	startedAt?: string;
	lastInteractionAt?: string;
	durationMs?: number;
	checkpointCount: number;
	turnCount?: number;
	tokenCount?: number;
	attribution?: InitialAttribution;
	lastCheckpointId?: string;
	author?: string;
	worktreePath?: string;
	worktreeId?: string;
	baseCommit?: string;
	transcriptPath?: string;
	hasShadowBranch: boolean;
	isStuck: boolean;
	canRunDoctor: boolean;
	canOpenLastCheckpoint: boolean;
	canOpenTranscript: boolean;
	searchText: string;
}

/** Normalized model for a checkpoint browser card. */
export interface EntireCheckpointCard {
	id: string;
	checkpointId?: string;
	rewindPointId?: string;
	promptPreview: string;
	displayHash: string;
	agent?: string;
	model?: string;
	status: SessionStatus;
	author?: string;
	timestamp?: string;
	branch?: string;
	tokenCount?: number;
	stepCount?: number;
	fileCount?: number;
	sessionCount: number;
	attribution?: InitialAttribution;
	summary?: SummaryRecord;
	primaryCommit?: AssociatedCommitModel;
	associatedCommitCount: number;
	diffSummary?: DiffSummaryModel;
	rewindAvailability?: RewindAvailability;
	isEphemeral: boolean;
	searchText: string;
}

/** A commit that has one or more checkpoints associated it it */
export interface CheckpointCommit {
	sha: string;
	shortSha: string;
	message: string;
	body?: string;
	authorName: string;
	authorEmail?: string;
	authoredAt?: string;
	fileStats?: FileDiffStat[];
	patchText?: string;
	checkpointIds: string[];
}

export interface ResolvedCheckpointRef {
	checkpointId: string;
	summary: CheckpointSummaryRecord | null;
	rewindPoints: NormalizedRewindPoint[];
}

export interface CommitCheckpointGroup {
	commit: CheckpointCommit;
	diffSummary?: DiffSummaryModel,
	checkpoints: ResolvedCheckpointRef[];
}

/** Groups checkpoint-linked commits under a shared authored day label for the tree view. */
export interface CheckpointDateGroup {
	timestamp: string;
	formattedDate: string;
	checkpointCommits: CommitCheckpointGroup[];
}

/** Lightweight model used to render the checkpoint tree without detail hydration. */
export interface CheckpointSummaryModel {
	id: string;
	checkpointId?: string;
	timestamp?: string;
	agent?: string;
	model?: string;
	author?: string;
	fileCount?: number;
	primaryCommit?: AssociatedCommitModel;
	diffSummary?: DiffSummaryModel;
	searchText: string;
}

/** Structured detail payload for a committed or temporary checkpoint item. */

