	promptPreview: string;
	status: SessionStatus;
	agent?: string;
	model?: string;
	author?: string;
	startedAt?: string;
	lastActivityAt?: string;
	durationMs?: number;
	attribution?: InitialAttribution;
	checkpointCount: number;
	turnCount?: number;
	toolCount?: number;
	tokenCount?: number;
	transcriptPath?: string;
}

/** Avatar/logo metadata for a rendered conversation turn. */
export interface SessionConversationActor {
	kind: "user" | "agent";
	initials: string;
	imageUri?: string;
}

/** Compact tool activity row rendered inline within a conversation turn. */
export interface SessionToolActivity {
	id: string;
	kind: "tool_use";
	label: string;
	detail?: string;
}

/** Human-readable conversation turn rendered in the session details panel. */
export interface SessionConversationTurn {
	id: string;
	actor: SessionConversationActor;
	timestamp?: string;
	text?: string;
	toolActivities: SessionToolActivity[];
}

/** Structured detail payload for the session details webview panel. */
export interface EntireSessionDetailModel {
	sessionId: string;
	source: "live" | "checkpoint";
	promptPreview: string;
	status: SessionStatus;
	startedAt?: string;
	lastActivityAt?: string;
	durationMs?: number;
	checkpointCount: number;
	turnCount?: number;
	toolCount?: number;
	tokenCount?: number;
	attribution?: InitialAttribution;
	model?: string;
	transcriptAvailable: boolean;
	turns: SessionConversationTurn[];
}

/** Per-file diff statistics aggregated from active-branch associated commits. */
export interface FileDiffStat {
	path: string;
	additions?: number;
	deletions?: number;
}

/** Rollup of changed-file counts and numeric line deltas for a checkpoint. */
export interface DiffSummaryModel {
	filesChanged: number;
	linesAdded?: number;
	linesRemoved?: number;
}

/** Commit metadata associated with a checkpoint on the active branch. */
export interface AssociatedCommitModel {
	sha: string;
	shortSha: string;
	message: string;
	body?: string;
	authorName: string;
	authorEmail?: string;
	authoredAt?: string;
	fileStats?: FileDiffStat[];
	patchText?: string;
}

/** Current rewindability and rewind-mode metadata for a checkpoint or temporary point. */
export interface RewindAvailability {
	isAvailable: boolean;
	pointId?: string;
	checkpointId?: string;
	isLogsOnly: boolean;
	isTaskCheckpoint: boolean;
	isTemporary: boolean;
	message?: string;
	sessionId?: string;
}

/** Normalized model for a session browser card. */
export interface EntireSessionCard {
	id: string;
	sessionId: string;
	promptPreview: string;
	displayHash?: string;
	checkpointIds: string[];
